clc; clear; close all; I = 1; A = [0 1; 0 0]; B = [0; 1/I]; Q = [10 0; 0 1]; R = 1; K = lqr(A, B, Q, R); Kp = 15; Ki = 2; Kd = 5; dt = 0.01; t = 0:dt:10; x_lqr = [0.5; 0]; x_pid = [0.5; 0]; integral = 0; prev_error = x_pid(1); lqr_response = zeros(size(t)); pid_response = zeros(size(t)); u_lqr_list = zeros(size(t)); u_pid_list = zeros(size(t)); for i = 1:length(t) ti = t(i); disturbance = 0.2*sin(2*ti); u_lqr = -K*x_lqr; x_lqr = x_lqr + (A*x_lqr + B*u_lqr + B*disturbance)*dt; lqr_response(i) = x_lqr(1); u_lqr_list(i) = u_lqr; error = x_pid(1); integral = integral + error*dt; derivative = (error - prev_error)/dt; u_pid = -(Kp*error + Ki*integral + Kd*derivative); prev_error = error; x_pid = x_pid + (A*x_pid + B*u_pid + B*disturbance)*dt; pid_response(i) = x_pid(1); u_pid_list(i) = u_pid; end figure; plot(t, lqr_response, 'LineWidth', 2, 'Color', 'blue'); hold on; plot(t, pid_response, 'LineWidth', 2, 'Color', 'red'); xlabel('Time (s)', 'FontSize', 12); ylabel('Angle (rad)', 'FontSize', 12); title('Rocket Pitch Angle: LQR vs PID Controller', 'FontSize', 14, 'FontWeight', 'bold'); legend('LQR', 'PID', 'FontSize', 11, 'Location', 'best'); grid on; grid minor; figure; plot(t, u_lqr_list, 'LineWidth', 2, 'Color', 'blue'); hold on; plot(t, u_pid_list, 'LineWidth', 2, 'Color', 'red'); xlabel('Time (s)', 'FontSize', 12); ylabel('Control Input', 'FontSize', 12); title('Control Effort: LQR vs PID Controller', 'FontSize', 14, 'FontWeight', 'bold'); legend('LQR', 'PID', 'FontSize', 11, 'Location', 'best'); grid on; grid minor; settling_time_lqr = find(abs(lqr_response(100:end)) < 0.01*abs(lqr_response(1)), 1) + 100; settling_time_pid = find(abs(pid_response(100:end)) < 0.01*abs(pid_response(1)), 1) + 100; overshoot_lqr = (max(lqr_response) - 0) / abs(lqr_response(1)) * 100; overshoot_pid = (max(pid_response) - 0) / abs(pid_response(1)) * 100; fprintf('\n===== Performance Comparison =====\n'); fprintf('LQR Controller:\n'); fprintf('  Settling Time: %.2f s\n', settling_time_lqr*dt); fprintf('  Overshoot: %.2f %%\n', overshoot_lqr); fprintf('  Peak Control Input: %.2f\n', max(abs(u_lqr_list))); fprintf('\nPID Controller:\n'); fprintf('  Settling Time: %.2f s\n', settling_time_pid*dt); fprintf('  Overshoot: %.2f %%\n', overshoot_pid); fprintf('  Peak Control Input: %.2f\n', max(abs(u_pid_list))); fprintf('==================================\n\n');